import heapq

class Solution(object):
    def minOperations(self, n, m):
        # Sieve primes up to 9999
        limit = 10000
        is_prime = [False, False] + [True] * (limit - 1)
        for i in range(2, int(limit**0.5) + 1):
            if is_prime[i]:
                for j in range(i*i, limit, i):
                    is_prime[j] = False

        if is_prime[n] or is_prime[m]:
            return -1

        # Dijkstra: cost = sum of all intermediate values including n and m
        # Each state is a number; cost to reach x = sum of values visited
        INF = float('inf')
        dist = {n: n}  # cost = n (first step costs n itself)
        heap = [(n, n)]  # (cost, current_number)
        while heap:
            cost, cur = heapq.heappop(heap)
            if cost > dist.get(cur, INF):
                continue
            if cur == m:
                return cost
            s = str(cur)
            for i in range(len(s)):
                # Increment digit i
                if s[i] != '9':
                    nxt = int(s[:i] + str(int(s[i])+1) + s[i+1:])
                    if not is_prime[nxt]:
                        ncost = cost + nxt
                        if ncost < dist.get(nxt, INF):
                            dist[nxt] = ncost
                            heapq.heappush(heap, (ncost, nxt))
                # Decrement digit i
                if s[i] != '0':
                    nxt = int(s[:i] + str(int(s[i])-1) + s[i+1:])
                    if not is_prime[nxt] and (len(str(nxt)) == len(s) or nxt == 0):
                        # Avoid leading zeros: skip if length changes (except becoming 0)
                        if len(str(nxt)) == len(s):
                            ncost = cost + nxt
                            if ncost < dist.get(nxt, INF):
                                dist[nxt] = ncost
                                heapq.heappush(heap, (ncost, nxt))
        return -1
